from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle different entities properly
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Use the first subject as the main subject
    main_subject = triples[0].subject
    main_clauses: list[str] = []
    related_clauses: list[str] = []

    def format_date(date_str: str) -> str:
        """Format date strings to be more natural."""
        date_str = date_str.strip('"')
        if '-' in date_str:
            parts = date_str.split('-')
            if len(parts) == 3:
                year, month, day = parts
                try:
                    month_names = ["January", "February", "March", "April", "May", "June",
                                   "July", "August", "September", "October", "November", "December"]
                    month_idx = int(month) - 1
                    if 0 <= month_idx < 12:
                        return f"{month_names[month_idx]} {day}, {year}"
                except (ValueError, IndexError):
                    pass
        return date_str

    def get_clause(triple: Triple, is_related: bool = False) -> str:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural‑language fragments
        if p == "category":
            return f"which is a {o}" if is_related else f"a {o}"
        elif p == "country":
            return f"which is in the {o}" if is_related else f"in the {o}"
        elif p == "location":
            return f"located in {o}"
        elif p == "municipality":
            return f"municipality of {o}"
        elif p == "state":
            return f"state of {o}"
        elif p == "district":
            return f"district of {o}"
        elif p in ("established", "foundingDate"):
            formatted = format_date(o)
            return f"established in {formatted}"
        elif p in ("owner", "owningOrganisation"):
            return f"owned by {o}"
        elif p == "inaugurationDate":
            formatted = format_date(o)
            return f"inaugurated on {formatted}"
        elif p == "capital":
            return f"capital is {o}"
        elif p == "legislature":
            return f"legislature is {o}"
        elif p == "dedicatedTo":
            return f"dedicated to {o}"
        elif p == "designer":
            return f"designed by {o}"
        elif p == "material":
            return f"made of {o}"
        elif p == "ethnicGroup":
            return f"ethnic group is {o}"
        elif p == "language":
            return f"language is {o}"
        elif p == "religion":
            return f"religion is {o}"
        elif p == "nearestCity":
            return f"nearest city is {o}"
        elif p == "currency":
            return f"currency is {o}"
        elif p == "largestCity":
            return f"largest city is {o}"
        elif p == "leader":
            return f"leader is {o}"
        elif p == "leaderTitle":
            return f"leader title is {o}"
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            return f"{direction} {o}"
        elif p == "nativeName":
            return f'native name "{o}"'
        else:
            # Fallback for any unexpected predicate
            return f"{p} {o}"

    # Process main subject triples
    for triple in subject_triples.get(main_subject, []):
        main_clauses.append(get_clause(triple, is_related=False))

    # Process related subject triples (like country info)
    for sub, sub_triples in subject_triples.items():
        if sub != main_subject:
            for triple in sub_triples:
                clause = get_clause(triple, is_related=True)
                related_clauses.append(f"{sub} {clause}")

    # Build the sentence with proper structure
    if main_clauses:
        sentence = f"{main_subject}"
        for i, clause in enumerate(main_clauses):
            if i == 0:
                sentence += f" {clause}"
            else:
                sentence += f", {clause}"
    else:
        sentence = main_subject

    if related_clauses:
        # Add related information as a relative clause
        if len(related_clauses) == 1:
            sentence += f", where {related_clauses[0]}"
        else:
            sentence += f", where {', '.join(related_clauses)}"

    sentence += "."
    return sentence

# EVOLVE-BLOCK-END
